// Parse CLI args. Supports --name <value> and --shout.
function parseArgs(argv) {
  const out = { name: "world", shout: false };
  for (let i = 0; i < argv.length; i++) {
    if (argv[i] === "--name") out.name = argv[++i];
    else if (argv[i] === "--shout") out.shout = true;
  }
  return out;
}
module.exports = { parseArgs };
